import Image from '@/components/image';
import { useTheme } from '@/components/theme-provider';
import { Card } from '@/components/ui/card';
import { Checkbox } from '@/components/ui/checkbox';
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from '@/components/ui/popover';
import { Switch } from '@/components/ui/switch';
import { IChunk } from '@/interfaces/database/knowledge';
import { CheckedState } from '@radix-ui/react-checkbox';
import classNames from 'classnames';
import DOMPurify from 'dompurify';
import { useEffect, useMemo, useState } from 'react';
import { useTranslation } from 'react-i18next';
import { ChunkTextMode } from '../../constant';
import styles from './index.less';

interface IProps {
  item: IChunk;
  checked: boolean;
  switchChunk: (available?: number, chunkIds?: string[]) => void;
  editChunk: (chunkId: string) => void;
  handleCheckboxClick: (chunkId: string, checked: boolean) => void;
  selected: boolean;
  clickChunkCard: (chunkId: string) => void;
  textMode: ChunkTextMode;
}

const estimateTokenCount = (content = '') => {
  const plainText = content.replace(/<[^>]+>/g, ' ').trim();
  if (!plainText) {
    return 0;
  }

  const cjkCount = (plainText.match(/[\u3400-\u9fff]/g) || []).length;
  const latinWordCount =
    plainText.replace(/[\u3400-\u9fff]/g, ' ').match(/[A-Za-z0-9_]+/g)
      ?.length || 0;

  return cjkCount + latinWordCount;
};

const ChunkCard = ({
  item,
  checked,
  handleCheckboxClick,
  editChunk,
  switchChunk,
  selected,
  clickChunkCard,
  textMode,
}: IProps) => {
  const available = Number(item.available_int);
  const [enabled, setEnabled] = useState(false);
  const { theme } = useTheme();
  const { t } = useTranslation();

  const onChange = (checked: boolean) => {
    setEnabled(checked);
    switchChunk(available === 0 ? 1 : 0, [item.chunk_id]);
  };

  const handleCheck = (e: CheckedState) => {
    handleCheckboxClick(item.chunk_id, e === 'indeterminate' ? false : e);
  };

  const handleContentDoubleClick = () => {
    editChunk(item.chunk_id);
  };

  const handleContentClick = () => {
    clickChunkCard(item.chunk_id);
  };

  useEffect(() => {
    setEnabled(available === 1);
  }, [available]);

  const keywordTags = (item.important_kwd || []).filter(Boolean);
  const questionTags = (item.question_kwd || []).filter(Boolean);
  const [open, setOpen] = useState<boolean>(false);
  const tokenNum = useMemo(() => {
    if (typeof item.token_num === 'number' && Number.isFinite(item.token_num)) {
      return item.token_num;
    }
    return estimateTokenCount(item.content_with_weight || '');
  }, [item.content_with_weight, item.token_num]);

  const renderTags = (tags: string[], tagClassName: string) => {
    if (tags.length === 0) {
      return <span className={styles.emptyTag}>--</span>;
    }

    return tags.map((tag, index) => (
      <span
        key={`${item.chunk_id}-${tag}-${index}`}
        className={classNames(styles.tagPill, tagClassName)}
      >
        {tag}
      </span>
    ));
  };

  return (
    <Card
      className={classNames(styles.chunkCard, {
        [`${theme === 'dark' ? styles.cardSelectedDark : styles.cardSelected}`]:
          selected,
      })}
    >
      <div className={styles.cardHeader}>
        <div className={styles.headerLeft}>
          <Checkbox onCheckedChange={handleCheck} checked={checked}></Checkbox>
          <span className={styles.chunkId}>#{item.chunk_id.slice(0, 8)}</span>
          <span
            className={classNames(styles.statusPill, {
              [styles.statusEnabled]: enabled,
              [styles.statusDisabled]: !enabled,
            })}
          >
            {enabled ? t('chunk.enabled') : t('chunk.disabled')}
          </span>
        </div>

        <div className={styles.headerRight}>
          <span className={styles.tokenTag}>{`${tokenNum} Tokens`}</span>
          <Switch
            checked={enabled}
            onCheckedChange={onChange}
            aria-readonly
            className="!m-0"
          />
        </div>
      </div>

      <div className={styles.cardBody}>
        {item.image_id && (
          <Popover open={open}>
            <PopoverTrigger
              asChild
              onMouseEnter={() => setOpen(true)}
              onMouseLeave={() => setOpen(false)}
            >
              <div>
                <Image id={item.image_id} className={styles.image}></Image>
              </div>
            </PopoverTrigger>
            <PopoverContent
              className="p-0"
              align={'start'}
              side={'right'}
              sideOffset={-20}
            >
              <div>
                <Image
                  id={item.image_id}
                  className={styles.imagePreview}
                ></Image>
              </div>
            </PopoverContent>
          </Popover>
        )}

        <section
          onDoubleClick={handleContentDoubleClick}
          onClick={handleContentClick}
          className={styles.content}
        >
          <div
            dangerouslySetInnerHTML={{
              __html: DOMPurify.sanitize(item.content_with_weight),
            }}
            className={classNames(styles.contentText, {
              [styles.contentEllipsis]: textMode === ChunkTextMode.Ellipse,
            })}
          ></div>
        </section>
      </div>

      <div className={styles.tagPanel}>
        <div className={styles.tagLine}>
          <span className={styles.tagTitle}>{t('chunk.keyword')}</span>
          <div className={styles.tagList}>
            {renderTags(keywordTags, styles.keywordTag)}
          </div>
        </div>
        <div className={styles.tagLine}>
          <span className={styles.tagTitle}>{t('chunk.question')}</span>
          <div className={styles.tagList}>
            {renderTags(questionTags, styles.questionTag)}
          </div>
        </div>
      </div>
    </Card>
  );
};

export default ChunkCard;
