import { formatDate } from '@/utils/date';
import { formatBytes } from '@/utils/file-util';

type Props = {
  size?: number;
  name?: string;
  create_date?: string;
};

export default ({ size, name, create_date }: Props) => {
  const sizeName = typeof size === 'number' ? formatBytes(size) : '--';
  const dateStr = create_date ? formatDate(create_date) : '--';
  const fileExt = name?.split('.').pop()?.toUpperCase() || 'FILE';

  return (
    <div className="flex flex-col gap-2">
      <div className="flex items-center gap-2">
        <span className="inline-flex h-[24px] items-center rounded-full border border-[#e5e7eb] bg-[#f3f4f6] px-[10px] text-[12px] font-medium leading-none text-[#4b5563]">
          {fileExt}
        </span>
        <h2 className="text-[22px] font-semibold text-[#1f2937] truncate">
          {name || '--'}
        </h2>
      </div>
      <div className="text-[13px] text-[#64748b]">
        Size: {sizeName} | Uploaded: {dateStr}
      </div>
    </div>
  );
};
