import HightLightMarkdown from '@/components/highlight-markdown';
import { useGetKnowledgeSearchParams } from '@/hooks/route-hook';
import {
  useFetchNextChunkList,
  useSwitchChunk,
} from '@/hooks/use-chunk-request';
import kbService, { listDocument } from '@/services/knowledge-service';
import {
  CheckCircleOutlined,
  ReloadOutlined,
  SaveOutlined,
} from '@ant-design/icons';
import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import { Button, Empty, Input, Modal, Select } from 'antd';
import { useCallback, useEffect, useMemo, useState } from 'react';
import { useTranslation } from 'react-i18next';
import { useNavigate } from 'umi';
import ChunkCard from './components/chunk-card';
import CreatingModal from './components/chunk-creating-modal';
import DocumentPreview from './components/document-preview';
import {
  useChangeChunkTextMode,
  useDeleteChunkByIds,
  useGetChunkHighlights,
  useHandleChunkCardClick,
  useUpdateChunk,
} from './hooks';

import ChunkResultBar from './components/chunk-result-bar';
import CheckboxSets from './components/chunk-result-bar/checkbox-sets';
import DocumentHeader from './components/document-preview/document-header';

import message from '@/components/ui/message';
import {
  RAGFlowPagination,
  RAGFlowPaginationType,
} from '@/components/ui/ragflow-pagination';
import { Spin } from '@/components/ui/spin';
import { SideBar } from '@/pages/dataset/sidebar';
import { useGetDocumentUrl } from '../../../knowledge-chunk/components/document-preview/hooks';
import styles from './index.less';

type OcrReviewLine = {
  id: string;
  text: string;
  page?: number | null;
};

type OcrReviewData = {
  doc_id: string;
  review_required: boolean;
  status: string;
  active_version_id: string;
  committed_version_id: string;
  versions: Array<{
    id: string;
    source?: string;
    label?: string;
    created_at?: string;
    created_by?: string;
    line_count?: number;
  }>;
  active_lines: OcrReviewLine[];
};

const Chunk = () => {
  const navigate = useNavigate();
  const { knowledgeId } = useGetKnowledgeSearchParams();
  const queryClient = useQueryClient();
  const [selectedChunkIds, setSelectedChunkIds] = useState<string[]>([]);
  const [ocrLines, setOcrLines] = useState<OcrReviewLine[]>([]);
  const [ocrDirty, setOcrDirty] = useState(false);
  const [refreshingOcrReview, setRefreshingOcrReview] = useState(false);
  const [ocrSelectedVersionId, setOcrSelectedVersionId] = useState<string>('');
  const [editingLineIndex, setEditingLineIndex] = useState<number | null>(null);
  const [editingLineText, setEditingLineText] = useState('');
  const { removeChunk } = useDeleteChunkByIds();
  const {
    data: { documentInfo, data = [], total },
    pagination,
    loading,
    searchString,
    handleInputChange,
    available,
    handleSetAvailable,
  } = useFetchNextChunkList();
  const { handleChunkCardClick, selectedChunkId } = useHandleChunkCardClick();

  const { t } = useTranslation();
  const { changeChunkTextMode, textMode } = useChangeChunkTextMode();
  const { switchChunk } = useSwitchChunk();
  const [chunkList, setChunkList] = useState(data);
  const {
    chunkUpdatingLoading,
    onChunkUpdatingOk,
    showChunkUpdatingModal,
    hideChunkUpdatingModal,
    chunkId,
    chunkUpdatingVisible,
    documentId,
  } = useUpdateChunk();
  const fileUrl = useGetDocumentUrl();
  const isPdf = documentInfo?.type === 'pdf';
  const ocrReviewConfig = documentInfo?.parser_config?.ocr_review;
  const reviewRequired = Boolean(isPdf && ocrReviewConfig?.review_required);
  const reviewCommitted = ocrReviewConfig?.status === 'committed';
  const reviewOnlyMode = Boolean(reviewRequired && !reviewCommitted);

  const { data: ocrReviewData, isFetching: ocrReviewFetching } =
    useQuery<OcrReviewData>({
      queryKey: ['ocr-review', documentId],
      enabled: Boolean(documentId && reviewOnlyMode),
      gcTime: 0,
      queryFn: async () => {
        const { data } = await kbService.ocr_review({
          doc_id: documentId,
        });
        if (data.code !== 0) {
          throw new Error(data.message || t('chunk.ocrReviewLoadFailed'));
        }
        return data.data;
      },
      retry: false,
    });

  const {
    mutateAsync: activateOcrReviewVersion,
    isPending: activateOcrReviewVersionLoading,
  } = useMutation({
    mutationKey: ['activate-ocr-review', documentId],
    mutationFn: async (versionId: string) => {
      const { data } = await kbService.ocr_review_activate({
        doc_id: documentId,
        version_id: versionId,
      });
      if (data.code !== 0) {
        throw new Error(
          data.message || t('chunk.ocrReviewSwitchVersionFailed'),
        );
      }
      return data.data;
    },
  });

  const { mutateAsync: saveOcrReview, isPending: saveOcrReviewLoading } =
    useMutation({
      mutationKey: ['save-ocr-review', documentId],
      mutationFn: async ({ lines }: { lines: OcrReviewLine[] }) => {
        const { data } = await kbService.ocr_review_save({
          doc_id: documentId,
          lines,
          label: t('chunk.ocrReviewEditedLabel'),
        });
        if (data.code !== 0) {
          throw new Error(data.message || t('chunk.ocrReviewSaveFailed'));
        }
        return data.data;
      },
    });

  const { mutateAsync: commitOcrReview, isPending: commitOcrReviewLoading } =
    useMutation({
      mutationKey: ['commit-ocr-review', documentId],
      mutationFn: async ({
        lines,
        versionId,
      }: {
        lines: OcrReviewLine[];
        versionId?: string;
      }) => {
        const { data } = await kbService.ocr_review_commit({
          doc_id: documentId,
          lines,
          version_id: versionId,
        });
        if (data.code !== 0) {
          throw new Error(data.message || t('chunk.ocrReviewCommitFailed'));
        }
        return data.data;
      },
    });

  useEffect(() => {
    setChunkList(data);
  }, [data]);

  useEffect(() => {
    setOcrDirty(false);
    setOcrSelectedVersionId('');
    setEditingLineIndex(null);
    setEditingLineText('');
  }, [documentId]);

  useEffect(() => {
    if (ocrReviewData?.active_lines && !ocrDirty) {
      setOcrLines(ocrReviewData.active_lines);
      setOcrSelectedVersionId(ocrReviewData.active_version_id || '');
    }
  }, [ocrReviewData, ocrDirty]);

  const onPaginationChange: RAGFlowPaginationType['onChange'] = (
    page,
    size,
  ) => {
    setSelectedChunkIds([]);
    pagination.onChange?.(page, size);
  };

  const selectAllChunk = useCallback(
    (checked: boolean) => {
      setSelectedChunkIds(checked ? data.map((x) => x.chunk_id) : []);
    },
    [data],
  );

  const handleSingleCheckboxClick = useCallback(
    (chunkId: string, checked: boolean) => {
      setSelectedChunkIds((previousIds) => {
        const idx = previousIds.findIndex((x) => x === chunkId);
        const nextIds = [...previousIds];
        if (checked && idx === -1) {
          nextIds.push(chunkId);
        } else if (!checked && idx !== -1) {
          nextIds.splice(idx, 1);
        }
        return nextIds;
      });
    },
    [],
  );

  const showSelectedChunkWarning = useCallback(() => {
    message.warning(t('message.pleaseSelectChunk'));
  }, [t]);

  const handleRemoveChunk = useCallback(async () => {
    if (selectedChunkIds.length > 0) {
      const resCode: number = await removeChunk(selectedChunkIds, documentId);
      if (resCode === 0) {
        setSelectedChunkIds([]);
      }
    } else {
      showSelectedChunkWarning();
    }
  }, [selectedChunkIds, documentId, removeChunk, showSelectedChunkWarning]);

  const handleSwitchChunk = useCallback(
    async (available?: number, chunkIds?: string[]) => {
      let ids = chunkIds;
      if (!chunkIds) {
        ids = selectedChunkIds;
        if (selectedChunkIds.length === 0) {
          showSelectedChunkWarning();
          return;
        }
      }

      const resCode: number = await switchChunk({
        chunk_ids: ids,
        available_int: available,
        doc_id: documentId,
      });
      if (ids?.length && resCode === 0) {
        chunkList.forEach((x: any) => {
          if (ids.indexOf(x['chunk_id']) > -1) {
            x['available_int'] = available;
          }
        });
        setChunkList(chunkList);
      }
    },
    [
      switchChunk,
      documentId,
      selectedChunkIds,
      showSelectedChunkWarning,
      chunkList,
    ],
  );

  const { highlights, setWidthAndHeight } =
    useGetChunkHighlights(selectedChunkId);

  const fileType = useMemo(() => {
    switch (documentInfo?.type) {
      case 'doc':
        return documentInfo?.name.split('.').pop() || 'doc';
      case 'visual':
      case 'docx':
      case 'txt':
      case 'md':
      case 'pdf':
        return documentInfo?.type;
    }
    return 'unknown';
  }, [documentInfo]);

  const hasValidOcrContent = useMemo(
    () => ocrLines.some((line) => line.text.trim().length > 0),
    [ocrLines],
  );

  const reviewStatus = useMemo(() => {
    return ocrReviewData?.status || ocrReviewConfig?.status || 'none';
  }, [ocrReviewConfig?.status, ocrReviewData?.status]);

  const reviewStatusLabel = useMemo(() => {
    if (reviewStatus === 'committed') {
      return t('chunk.ocrReviewStatusCommitted');
    }
    if (reviewStatus === 'reviewing') {
      return t('chunk.ocrReviewStatusReviewing');
    }
    if (reviewStatus === 'pending') {
      return t('chunk.ocrReviewStatusPending');
    }
    return t('chunk.ocrReviewStatusNone');
  }, [reviewStatus, t]);

  const ocrVersionOptions = useMemo(() => {
    return (ocrReviewData?.versions ?? []).map((version) => ({
      label: `${version.label || version.id} (${version.line_count || 0})`,
      value: version.id,
    }));
  }, [ocrReviewData]);

  const isEditingSegment = editingLineIndex !== null;
  const editingOriginalText = useMemo(() => {
    if (editingLineIndex === null) {
      return '';
    }
    return ocrLines[editingLineIndex]?.text ?? '';
  }, [editingLineIndex, ocrLines]);
  const editingChanged = useMemo(() => {
    if (editingLineIndex === null) {
      return false;
    }
    return editingLineText !== editingOriginalText;
  }, [editingLineIndex, editingLineText, editingOriginalText]);

  const handleRefreshOcrReview = useCallback(async () => {
    if (!documentId || !isPdf || !reviewOnlyMode || isEditingSegment) {
      return;
    }
    try {
      setRefreshingOcrReview(true);
      await kbService.ocr_review_init({
        doc_ids: [documentId],
        force: true,
      });
      await queryClient.invalidateQueries({
        queryKey: ['ocr-review', documentId],
      });
      setOcrDirty(false);
    } catch (error: any) {
      message.error(error?.message || t('chunk.ocrReviewLoadFailed'));
    } finally {
      setRefreshingOcrReview(false);
    }
  }, [documentId, isEditingSegment, isPdf, queryClient, reviewOnlyMode, t]);

  const handleSaveOcrReview = useCallback(async () => {
    if (!documentId || !isPdf || !reviewOnlyMode || isEditingSegment) {
      return;
    }
    if (!hasValidOcrContent) {
      message.warning(t('chunk.ocrReviewEmpty'));
      return;
    }
    try {
      const ret = await saveOcrReview({ lines: ocrLines });
      if (ret?.active_version_id) {
        setOcrSelectedVersionId(ret.active_version_id);
      }
      await queryClient.invalidateQueries({
        queryKey: ['ocr-review', documentId],
      });
      setOcrDirty(false);
      message.success(t('chunk.ocrReviewSaved'));
    } catch (error: any) {
      message.error(error?.message || t('chunk.ocrReviewSaveFailed'));
    }
  }, [
    documentId,
    hasValidOcrContent,
    isPdf,
    ocrLines,
    queryClient,
    reviewOnlyMode,
    saveOcrReview,
    t,
    isEditingSegment,
  ]);

  const navigateToDocumentList = useCallback(() => {
    if (knowledgeId) {
      navigate(`/dataset/dataset/${knowledgeId}`);
      return;
    }
    navigate('/datasets');
  }, [knowledgeId, navigate]);

  const navigateToReviewDocument = useCallback(
    (nextDocId: string) => {
      if (knowledgeId) {
        navigate(`/chunk/parsed/chunks?id=${knowledgeId}&doc_id=${nextDocId}`);
        return;
      }
      navigate('/datasets');
    },
    [knowledgeId, navigate],
  );

  const listPendingReviewDocs = useCallback(async () => {
    if (!knowledgeId) {
      return [] as Array<{ id: string }>;
    }

    const pageSize = 200;
    let page = 1;
    let total = 0;
    let docs: any[] = [];

    do {
      const ret = await listDocument(
        {
          kb_id: knowledgeId,
          page,
          page_size: pageSize,
        },
        {},
      );
      if (ret.data.code !== 0) {
        throw new Error(
          ret.data.message || t('chunk.ocrReviewListPendingFailed'),
        );
      }

      const currentDocs = Array.isArray(ret.data.data?.docs)
        ? ret.data.data.docs
        : [];
      total = Number(ret.data.data?.total || 0);
      docs = docs.concat(currentDocs);
      page += 1;
    } while (docs.length < total);

    return docs.filter(
      (doc) =>
        doc.id !== documentId &&
        doc.type === 'pdf' &&
        doc?.parser_config?.ocr_review?.review_required === true &&
        String(doc?.parser_config?.ocr_review?.status || '').toLowerCase() ===
          'reviewing',
    );
  }, [documentId, knowledgeId, t]);

  const handleCommitOcrReview = useCallback(async () => {
    if (!documentId || !isPdf || !reviewOnlyMode || isEditingSegment) {
      return;
    }
    if (!hasValidOcrContent) {
      message.warning(t('chunk.ocrReviewEmpty'));
      return;
    }
    try {
      let versionIdToCommit = ocrSelectedVersionId || undefined;
      if (ocrDirty) {
        const saveRet = await saveOcrReview({ lines: ocrLines });
        versionIdToCommit = saveRet?.active_version_id || versionIdToCommit;
      }
      await commitOcrReview({
        lines: ocrLines,
        versionId: versionIdToCommit,
      });
      setOcrDirty(false);
      setSelectedChunkIds([]);
      await Promise.all([
        queryClient.invalidateQueries({ queryKey: ['fetchChunkList'] }),
        queryClient.invalidateQueries({ queryKey: ['fetchDocumentList'] }),
        queryClient.invalidateQueries({ queryKey: ['ocr-review', documentId] }),
      ]);
    } catch (error: any) {
      message.error(error?.message || t('chunk.ocrReviewCommitFailed'));
      return;
    }

    try {
      const pendingReviewDocs = await listPendingReviewDocs();
      if (pendingReviewDocs.length > 0) {
        const nextDocId = pendingReviewDocs[0]?.id;
        Modal.confirm({
          title: t('chunk.ocrReviewNextTitle'),
          content: t('chunk.ocrReviewNextContent', {
            count: pendingReviewDocs.length,
          }),
          okText: t('chunk.ocrReviewNextOk'),
          cancelText: t('chunk.ocrReviewNextCancel'),
          onOk: () => {
            if (nextDocId) {
              navigateToReviewDocument(nextDocId);
              return;
            }
            navigateToDocumentList();
          },
          onCancel: () => {
            navigateToDocumentList();
          },
        });
        return;
      }

      Modal.info({
        title: t('chunk.ocrReviewAllDoneTitle'),
        content: t('chunk.ocrReviewAllDoneContent'),
        okText: t('common.ok'),
        onOk: () => {
          navigateToDocumentList();
        },
      });
    } catch (error: any) {
      message.warning(error?.message || t('chunk.ocrReviewListPendingFailed'));
      navigateToDocumentList();
    }
  }, [
    commitOcrReview,
    documentId,
    hasValidOcrContent,
    isPdf,
    ocrLines,
    ocrDirty,
    ocrSelectedVersionId,
    queryClient,
    reviewOnlyMode,
    saveOcrReview,
    t,
    isEditingSegment,
    listPendingReviewDocs,
    navigateToDocumentList,
    navigateToReviewDocument,
  ]);

  const handleSwitchOcrVersion = useCallback(
    async (versionId: string) => {
      if (!documentId || !versionId || isEditingSegment) {
        return;
      }
      try {
        const ret = await activateOcrReviewVersion(versionId);
        setOcrSelectedVersionId(versionId);
        setOcrLines(ret?.active_lines ?? []);
        setOcrDirty(false);
        setEditingLineIndex(null);
        setEditingLineText('');
      } catch (error: any) {
        message.error(
          error?.message || t('chunk.ocrReviewSwitchVersionFailed'),
        );
      }
    },
    [activateOcrReviewVersion, documentId, isEditingSegment, t],
  );

  const handleStartEditLine = useCallback(
    (idx: number) => {
      setEditingLineIndex(idx);
      setEditingLineText(ocrLines[idx]?.text ?? '');
    },
    [ocrLines],
  );

  const handleCancelEditLine = useCallback(() => {
    setEditingLineIndex(null);
    setEditingLineText('');
  }, []);

  const handleSaveEditLine = useCallback(() => {
    if (editingLineIndex === null) {
      return;
    }
    setOcrLines((previous) =>
      previous.map((line, idx) =>
        idx === editingLineIndex
          ? {
              ...line,
              text: editingLineText,
            }
          : line,
      ),
    );
    setOcrDirty(true);
    setEditingLineIndex(null);
    setEditingLineText('');
  }, [editingLineIndex, editingLineText]);

  return (
    <section className={styles.pageShell}>
      <SideBar />
      <div className={styles.chunkPage}>
        <div className={styles.contentArea}>
          <section className={styles.previewPanel}>
            <div className={styles.previewHeader}>
              <DocumentHeader {...documentInfo} />
            </div>
            <section className={styles.previewBody}>
              <DocumentPreview
                className={styles.documentPreview}
                fileType={fileType}
                highlights={highlights}
                setWidthAndHeight={setWidthAndHeight}
                url={fileUrl}
              ></DocumentPreview>
            </section>
          </section>

          <section className={styles.chunkPanel}>
            <Spin spinning={loading} className={styles.spin} size="large">
              <div className={styles.chunkHeader}>
                <div>
                  <h2 className={styles.chunkTitle}>
                    {reviewOnlyMode
                      ? t('chunk.ocrReviewTitle')
                      : t('chunk.chunkResult')}
                  </h2>
                  <div className={styles.chunkSubtitle}>
                    {reviewOnlyMode
                      ? t('chunk.ocrReviewTip')
                      : t('chunk.chunkResultTip')}
                  </div>
                </div>

                <div className={styles.metricInfo}>
                  {reviewOnlyMode
                    ? t('chunk.ocrReviewLineCount', { count: ocrLines.length })
                    : `Total ${total} · Selected ${selectedChunkIds.length}`}
                </div>
              </div>

              {reviewOnlyMode ? (
                <section className={styles.ocrReviewPanel}>
                  <div className={styles.ocrReviewHeader}>
                    <div>
                      <h3 className={styles.ocrReviewTitle}>
                        {t('chunk.ocrReviewTitle')}
                      </h3>
                      <p className={styles.ocrReviewDesc}>
                        {`${t('chunk.ocrReviewStatus')}: ${reviewStatusLabel}`}
                      </p>
                    </div>
                    <div className={styles.ocrReviewActions}>
                      <Button
                        icon={<ReloadOutlined />}
                        onClick={handleRefreshOcrReview}
                        loading={refreshingOcrReview}
                        disabled={isEditingSegment}
                      >
                        {t('chunk.ocrReviewReparse')}
                      </Button>
                      <Button
                        icon={<SaveOutlined />}
                        onClick={handleSaveOcrReview}
                        loading={saveOcrReviewLoading}
                        disabled={!ocrDirty || isEditingSegment}
                      >
                        {t('chunk.ocrReviewSave')}
                      </Button>
                      <Button
                        type="primary"
                        icon={<CheckCircleOutlined />}
                        onClick={handleCommitOcrReview}
                        loading={commitOcrReviewLoading}
                        disabled={
                          ocrReviewFetching ||
                          saveOcrReviewLoading ||
                          activateOcrReviewVersionLoading ||
                          isEditingSegment
                        }
                      >
                        {t('chunk.ocrReviewCommit')}
                      </Button>
                    </div>
                  </div>
                  <div className={styles.ocrReviewToolbar}>
                    <div className={styles.ocrReviewToolbarLeft}>
                      <Select
                        className={styles.ocrVersionSelect}
                        placeholder={t('chunk.ocrReviewVersionPlaceholder')}
                        value={ocrSelectedVersionId || undefined}
                        options={ocrVersionOptions}
                        onChange={handleSwitchOcrVersion}
                        loading={
                          ocrReviewFetching || activateOcrReviewVersionLoading
                        }
                        disabled={
                          ocrReviewFetching ||
                          saveOcrReviewLoading ||
                          commitOcrReviewLoading ||
                          activateOcrReviewVersionLoading ||
                          ocrDirty ||
                          isEditingSegment
                        }
                      />
                    </div>
                    <div className={styles.ocrReviewStat}>
                      <span>
                        {t('chunk.ocrReviewLineCount', {
                          count: ocrLines.length,
                        })}
                      </span>
                      {ocrDirty && (
                        <span className={styles.ocrReviewDirtyHint}>
                          {t('chunk.ocrReviewUnsaved')}
                        </span>
                      )}
                    </div>
                  </div>
                  <div className={styles.ocrReviewList}>
                    {ocrLines.length > 0 ? (
                      <div className={styles.ocrMarkdownCanvas}>
                        {ocrLines.map((line, idx) => {
                          const isActive = editingLineIndex === idx;
                          return (
                            <article
                              key={line.id || `${line.page}-${idx}`}
                              className={`${styles.ocrMarkdownSegment} ${
                                isActive ? styles.ocrMarkdownSegmentActive : ''
                              }`}
                              onClick={() => {
                                if (!isActive) {
                                  handleStartEditLine(idx);
                                }
                              }}
                            >
                              {isActive ? (
                                <>
                                  <Input.TextArea
                                    autoSize={{ minRows: 5, maxRows: 16 }}
                                    autoFocus
                                    value={editingLineText}
                                    onChange={(event) =>
                                      setEditingLineText(event.target.value)
                                    }
                                    onClick={(event) => {
                                      event.stopPropagation();
                                    }}
                                    placeholder={t(
                                      'chunk.ocrReviewLinePlaceholder',
                                    )}
                                  />
                                  <div className={styles.ocrSegmentEditActions}>
                                    <Button
                                      type="primary"
                                      onClick={handleSaveEditLine}
                                      disabled={!editingChanged}
                                    >
                                      {t('common.save')}
                                    </Button>
                                    <Button onClick={handleCancelEditLine}>
                                      {t('chunk.ocrReviewCancel')}
                                    </Button>
                                  </div>
                                </>
                              ) : (
                                <div className={styles.ocrReviewRendered}>
                                  {line.text.trim() ? (
                                    <HightLightMarkdown>
                                      {line.text}
                                    </HightLightMarkdown>
                                  ) : (
                                    <span
                                      className={styles.ocrReviewRenderedEmpty}
                                    >
                                      {t('chunk.ocrReviewPreviewEmpty')}
                                    </span>
                                  )}
                                </div>
                              )}
                            </article>
                          );
                        })}
                      </div>
                    ) : (
                      <div className={styles.ocrReviewEmpty}>
                        <Empty
                          image={Empty.PRESENTED_IMAGE_SIMPLE}
                          description={t('chunk.ocrReviewNoData')}
                        />
                      </div>
                    )}
                  </div>
                </section>
              ) : (
                <>
                  <ChunkResultBar
                    handleInputChange={handleInputChange}
                    searchString={searchString}
                    changeChunkTextMode={changeChunkTextMode}
                    createChunk={showChunkUpdatingModal}
                    available={available}
                    selectAllChunk={selectAllChunk}
                    handleSetAvailable={handleSetAvailable}
                  />

                  <CheckboxSets
                    selectAllChunk={selectAllChunk}
                    switchChunk={handleSwitchChunk}
                    removeChunk={handleRemoveChunk}
                    checked={
                      data.length > 0 && selectedChunkIds.length === data.length
                    }
                    selectedChunkIds={selectedChunkIds}
                  />

                  <div className={styles.pageContent}>
                    <div
                      className={`${styles.chunkContainer} flex flex-col gap-4`}
                    >
                      {chunkList.map((item) => (
                        <ChunkCard
                          item={item}
                          key={item.chunk_id}
                          editChunk={showChunkUpdatingModal}
                          checked={selectedChunkIds.some(
                            (x) => x === item.chunk_id,
                          )}
                          handleCheckboxClick={handleSingleCheckboxClick}
                          switchChunk={handleSwitchChunk}
                          clickChunkCard={handleChunkCardClick}
                          selected={item.chunk_id === selectedChunkId}
                          textMode={textMode}
                        ></ChunkCard>
                      ))}
                    </div>
                  </div>

                  <div className={styles.pageFooter}>
                    <RAGFlowPagination
                      pageSize={pagination.pageSize}
                      current={pagination.current}
                      total={total}
                      onChange={(page, pageSize) => {
                        onPaginationChange(page, pageSize);
                      }}
                    ></RAGFlowPagination>
                  </div>
                </>
              )}
            </Spin>
          </section>
        </div>
      </div>
      {chunkUpdatingVisible && !reviewOnlyMode && (
        <CreatingModal
          doc_id={documentId}
          chunkId={chunkId}
          hideModal={hideChunkUpdatingModal}
          visible={chunkUpdatingVisible}
          loading={chunkUpdatingLoading}
          onOk={onChunkUpdatingOk}
          parserId={documentInfo.parser_id}
        />
      )}
    </section>
  );
};

export default Chunk;
