import { Checkbox } from '@/components/ui/checkbox';
import { Label } from '@/components/ui/label';
import { Ban, CircleCheck, Trash2 } from 'lucide-react';
import { useCallback, useMemo } from 'react';
import { useTranslation } from 'react-i18next';

type ICheckboxSetProps = {
  selectAllChunk: (e: any) => void;
  removeChunk: (e?: any) => void;
  switchChunk: (available: number) => void;
  checked: boolean;
  selectedChunkIds: string[];
};
export default (props: ICheckboxSetProps) => {
  const {
    selectAllChunk,
    removeChunk,
    switchChunk,
    checked,
    selectedChunkIds,
  } = props;
  const { t } = useTranslation();
  const handleSelectAllCheck = useCallback(
    (e: any) => {
      console.log('eee=', e);
      selectAllChunk(e);
    },
    [selectAllChunk],
  );

  const handleDeleteClick = useCallback(() => {
    removeChunk();
  }, [removeChunk]);

  const handleEnabledClick = useCallback(() => {
    switchChunk(1);
  }, [switchChunk]);

  const handleDisabledClick = useCallback(() => {
    switchChunk(0);
  }, [switchChunk]);

  const isSelected = useMemo(() => {
    return selectedChunkIds?.length > 0;
  }, [selectedChunkIds]);

  return (
    <div className="flex flex-wrap items-center gap-6 py-2">
      <div className="flex items-center gap-2 cursor-pointer text-[#6b7280] hover:text-[#374151]">
        <Checkbox
          id="all_chunks_checkbox"
          onCheckedChange={handleSelectAllCheck}
          checked={checked}
          className="border-[#9ca3af] data-[state=checked]:border-[#6b7280] data-[state=checked]:bg-[#6b7280]"
        />
        <Label htmlFor="all_chunks_checkbox">{t('chunk.selectAll')}</Label>
      </div>
      {isSelected && (
        <>
          <div
            className="flex items-center cursor-pointer text-[#6b7280] hover:text-[#111827]"
            onClick={handleEnabledClick}
          >
            <CircleCheck size={16} />
            <span className="block ml-1">{t('chunk.enable')}</span>
          </div>
          <div
            className="flex items-center cursor-pointer text-[#6b7280] hover:text-[#111827]"
            onClick={handleDisabledClick}
          >
            <Ban size={16} />
            <span className="block ml-1">{t('chunk.disable')}</span>
          </div>
          <div
            className="flex items-center cursor-pointer text-[#ef4444] hover:text-[#dc2626]"
            onClick={handleDeleteClick}
          >
            <Trash2 size={16} />
            <span className="block ml-1">{t('chunk.delete')}</span>
          </div>
        </>
      )}
    </div>
  );
};
