import HightLightMarkdown from '@/components/highlight-markdown';
import message from '@/components/ui/message';
import { Spin } from '@/components/ui/spin';
import request from '@/utils/request';
import classNames from 'classnames';
import { useCallback, useEffect, useState } from 'react';
import styles from './index.less';

type MdPreviewerProps = { className?: string; url: string };

export const MdPreviewer = ({ className, url }: MdPreviewerProps) => {
  const [loading, setLoading] = useState(false);
  const [data, setData] = useState<string>('');

  const fetchMarkdown = useCallback(async () => {
    setLoading(true);
    const res = await request(url, {
      method: 'GET',
      responseType: 'blob',
      onError: (err: any) => {
        message.error('Failed to load markdown file');
        console.error('Error loading markdown file:', err);
        setLoading(false);
      },
    });
    const reader = new FileReader();
    reader.readAsText(res.data);
    reader.onload = () => {
      setData(reader.result as string);
      setLoading(false);
    };
  }, [url]);

  useEffect(() => {
    if (url) {
      fetchMarkdown();
    } else {
      setLoading(false);
      setData('');
    }
  }, [url, fetchMarkdown]);

  return (
    <div className={classNames(styles.previewShell, className)}>
      {loading && (
        <div className={styles.previewLoadingMask}>
          <Spin />
        </div>
      )}
      {!loading && (
        <div className={styles.markdownContent}>
          <HightLightMarkdown>{data}</HightLightMarkdown>
        </div>
      )}
    </div>
  );
};
